#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MAXQ 100005
int A[MAXN], B[MAXN];
int treeA[4 * MAXN], treeB[4 * MAXN];
void updateA(int node, int start, int end, int l, int r, int val) {
    if (start > end || start > r || end < l) return;
    if (start >= l && end <= r) {
        treeA[node] += val;
        return;
    }
    int mid = (start + end) / 2;
    updateA(2 * node, start, mid, l, r, val);
    updateA(2 * node + 1, mid + 1, end, l, r, val);
}
int queryA(int node, int start, int end, int l, int r) {
    if (start > end || start > r || end < l) return -1000000000;
    if (start >= l && end <= r) return treeA[node];
    int mid = (start + end) / 2;
    return treeA[node] + queryA(2 * node, start, mid, l, r) + queryA(2 * node + 1, mid + 1, end, l, r);
}
void updateB(int node, int start, int end, int l, int r, int val) {
    if (start > end || start > r || end < l) return;
    if (start >= l && end <= r) {
        treeB[node] += val;
        return;
    }
    int mid = (start + end) / 2;
    updateB(2 * node, start, mid, l, r, val);
    updateB(2 * node + 1, mid + 1, end, l, r, val);
}
int queryB(int node, int start, int end, int l, int r) {
    if (start > end || start > r || end < l) return -1000000000;
    if (start >= l && end <= r) return treeB[node];
    int mid = (start + end) / 2;
    return treeB[node] + queryB(2 * node, start, mid, l, r) + queryB(2 * node + 1, mid + 1, end, l, r);
}
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    for (int i = 1; i <= N; i++) scanf("%d", &A[i]);
    for (int i = 1; i <= N; i++) scanf("%d", &B[i]);
    for (int i = 1; i <= N; i++) treeA[i + N - 1] = A[i];
    for (int i = 1; i <= N; i++) treeB[i + N - 1] = B[i];
    for (int i = N - 1; i >= 1; i--) {
        treeA[i] = treeA[2 * i] + treeA[2 * i + 1];
        treeB[i] = treeB[2 * i] + treeB[2 * i + 1];
    }
    while (Q--) {
        int t, l, r, x;
        scanf("%d %d %d", &t, &l, &r);
        if (t == 1) {
            int maxA = queryA(1, 1, N, l, r);
            printf("%d\n", maxA);
        } else if (t == 2) {
            updateA(1, 1, N, l, r, queryB(1, 1, N, l, r));
        } else if (t == 3) {
            scanf("%d", &x);
            updateB(1, 1, N, l, r, x);
        } else if (t == 4) {
            scanf("%d", &x);
            updateA(1, 1, N, l, r, x);
        }
    }
    return 0;
}

